export class ProtocolParseError extends Error {
    constructor(message) {
        super(message);
        this.code = "INVALID_FRAME";
        this.name = "ProtocolParseError";
    }
}
export function parse(raw) {
    try {
        const obj = JSON.parse(raw);
        if (!obj || typeof obj !== "object") {
            throw new ProtocolParseError("Invalid JSON frame: not an object");
        }
        return obj;
    }
    catch (e) {
        if (e instanceof ProtocolParseError)
            throw e;
        throw new ProtocolParseError(`Failed to parse frame: ${e.message}`);
    }
}
